create extension if not exists pgcrypto;
create table if not exists public.profiles (id uuid primary key references auth.users(id) on delete cascade, full_name text, phone text, role text not null default 'customer' check (role in ('customer','agent','admin')), commission_rate numeric(5,4) not null default 0.1200 check (commission_rate >= 0 and commission_rate <= 1), created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.business_settings (id boolean primary key default true check (id), brand_name text not null default 'StayLedger', support_email text, default_commission_rate numeric(5,4) not null default 0.1200 check (default_commission_rate >= 0 and default_commission_rate <= 1), currency text not null default 'USD', liteapi_mode text not null default 'sandbox' check (liteapi_mode in ('sandbox','production')), created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.hotels_cache (id uuid primary key default gen_random_uuid(), liteapi_hotel_id text unique, name text not null, city text, country text, address text, stars numeric(2,1), rating numeric(3,2), image_url text, amenities jsonb not null default '[]'::jsonb, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.hotel_searches (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete set null, city text, country text, checkin date, checkout date, guests integer not null default 2 check (guests > 0), rooms integer not null default 1 check (rooms > 0), source text not null default 'portal', created_at timestamptz not null default now());
create table if not exists public.prebookings (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete set null, liteapi_prebook_id text unique, liteapi_offer_id text, hotel_id uuid references public.hotels_cache(id) on delete set null, checkin date, checkout date, guests integer not null default 2 check (guests > 0), currency text not null default 'USD', subtotal numeric(12,2) not null default 0, taxes numeric(12,2) not null default 0, total numeric(12,2) not null default 0, status text not null default 'pending' check (status in ('pending','expired','booked','failed')), expires_at timestamptz, raw_response jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.bookings (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete set null, prebooking_id uuid references public.prebookings(id) on delete set null, liteapi_booking_id text unique, client_reference text unique, holder_first_name text not null, holder_last_name text not null, holder_email text not null, hotel_name text not null, city text, checkin date, checkout date, currency text not null default 'USD', subtotal numeric(12,2) not null default 0, taxes numeric(12,2) not null default 0, total numeric(12,2) not null default 0, commission_rate numeric(5,4) not null default 0.1200, commission_amount numeric(12,2) generated always as (round((total * commission_rate), 2)) stored, status text not null default 'confirmed' check (status in ('pending','confirmed','cancelled','failed','refunded')), payment_status text not null default 'pending' check (payment_status in ('pending','authorized','paid','failed','refunded')), raw_response jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.booking_guests (id uuid primary key default gen_random_uuid(), booking_id uuid not null references public.bookings(id) on delete cascade, first_name text not null, last_name text not null, age integer check (age is null or age >= 0), is_holder boolean not null default false, created_at timestamptz not null default now());
create table if not exists public.commission_ledger (id uuid primary key default gen_random_uuid(), booking_id uuid not null references public.bookings(id) on delete cascade, amount numeric(12,2) not null, currency text not null default 'USD', status text not null default 'pending' check (status in ('pending','approved','paid','reversed')), notes text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.webhook_events (id uuid primary key default gen_random_uuid(), event_id text unique, event_name text not null, booking_id uuid references public.bookings(id) on delete set null, payload jsonb not null, processed_at timestamptz, created_at timestamptz not null default now());
create or replace function public.set_updated_at() returns trigger language plpgsql set search_path = public as $$ begin new.updated_at = now(); return new; end; $$;
do $$ begin perform 1; end $$;
alter table public.profiles enable row level security; alter table public.business_settings enable row level security; alter table public.hotels_cache enable row level security; alter table public.hotel_searches enable row level security; alter table public.prebookings enable row level security; alter table public.bookings enable row level security; alter table public.booking_guests enable row level security; alter table public.commission_ledger enable row level security; alter table public.webhook_events enable row level security;
create index if not exists idx_hotel_searches_user_id on public.hotel_searches(user_id); create index if not exists idx_prebookings_user_id on public.prebookings(user_id); create index if not exists idx_prebookings_hotel_id on public.prebookings(hotel_id); create index if not exists idx_bookings_user_id on public.bookings(user_id); create index if not exists idx_bookings_prebooking_id on public.bookings(prebooking_id); create index if not exists idx_booking_guests_booking_id on public.booking_guests(booking_id); create index if not exists idx_commission_ledger_booking_id on public.commission_ledger(booking_id); create index if not exists idx_webhook_events_booking_id on public.webhook_events(booking_id);
grant usage on schema public to anon, authenticated; grant select on public.business_settings to anon, authenticated; grant select on public.hotels_cache to anon, authenticated; grant select, insert, update on public.profiles to authenticated; grant select, insert on public.hotel_searches to authenticated; grant select, insert, update on public.prebookings to authenticated; grant select, insert, update on public.bookings to authenticated; grant select, insert, update on public.booking_guests to authenticated; grant select on public.commission_ledger to authenticated;
insert into public.business_settings (id, brand_name, default_commission_rate, currency, liteapi_mode) values (true, 'StayLedger', 0.1200, 'USD', 'sandbox') on conflict (id) do nothing;
